mapper.sql:
LEFT JOIN msf_admin_user_info AS ${regAdminUserAlias:regAdminUser}
  ON (SPLIT_PART(${auditTable}.cret_id, '|', 1) = 'A'
    AND ${regAdminUserAlias:regAdminUser}.admin_id = SPLIT_PART(${auditTable}.cret_id, '|', 2))
LEFT JOIN msf_admin_user_info AS ${modAdminUserAlias:modAdminUser}
  ON (SPLIT_PART(${auditTable}.amd_id, '|', 1) = 'A'
    AND ${modAdminUserAlias:modAdminUser}.admin_id = SPLIT_PART(${auditTable}.amd_id, '|', 2))
LEFT JOIN msf_user_info AS ${regFormUserAlias:regFormUser}
  ON (SPLIT_PART(${auditTable}.cret_id, '|', 1) = 'F'
    AND ${regFormUserAlias:regFormUser}.user_id = SPLIT_PART(${auditTable}.cret_id, '|', 2))
LEFT JOIN msf_user_info AS ${modFormUserAlias:modFormUser}
  ON (SPLIT_PART(${auditTable}.amd_id, '|', 1) = 'F'
    AND ${modFormUserAlias:modFormUser}.user_id = SPLIT_PART(${auditTable}.amd_id, '|', 2))
